import { neon } from '@neondatabase/serverless'

if (!process.env.DATABASE_URL) {
  throw new Error('DATABASE_URL environment variable is not set')
}

export const sql = neon(process.env.DATABASE_URL)

// Helper to execute queries with proper typing
export async function query<T>(
  queryText: TemplateStringsArray,
  ...values: unknown[]
): Promise<T[]> {
  const result = await sql(queryText, ...values)
  return result as T[]
}

// Transaction helper (Neon supports HTTP transactions)
export async function transaction<T>(
  callback: (sql: typeof import('@neondatabase/serverless').neon) => Promise<T>
): Promise<T> {
  // For Neon serverless, we use the same connection
  // Real transactions would require @neondatabase/serverless with Pool
  return callback(sql as unknown as typeof import('@neondatabase/serverless').neon)
}
